var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mmm...","TWN":"呃嗯……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"깼니?","JPN":"気がついたかしら？","ENG":"Finally awake, I see?","TWN":"醒了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……헤, 헤론 님?!","JPN":"……ヘ、ヘロン様！？","ENG":"M-madam H-Heron?!","TWN":"海……海倫夫人？！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아앗.","JPN":"ああっ。","ENG":"Aah...!","TWN":"噢嗚…"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머. 일어나면 안 돼. 아직 어지러울 거야.","JPN":"あら。起きたらダメよ。まだクラクラするでしょうから。","ENG":"Oh, don’t get up. You have a concussion.","TWN":"哎呀，你還不能起來，頭應該還很暈吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"안색이 안 좋아서 수액을 놓은 참이란다. 좀 괜찮니?","JPN":"顔色が悪かったから、今点滴を打ったのよ。大丈夫？","ENG":"You don’t look so good, so we were just about to give you an IV. Are you all right?","TWN":"你臉色不太好，正在幫你打點滴，感覺還好嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여기는…….","JPN":"ここは……","ENG":"Where am I…?","TWN":"這裡是……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아! 그게 궁금했구나?","JPN":"ああ！　それが気になってたのね。","ENG":"Oh! Is that what you want to know?","TWN":"你好奇嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드야. 네가 쭉 지내왔던 곳.","JPN":"ウィザードよ。あなたがずっと暮らしてきた場所。","ENG":"You’re at Wizard... The place you grew up.","TWN":"這裡是魔法師，就是你長大的地方。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……역시 알고 계셨네요.","JPN":"……やっぱり知ってたんですね。","ENG":"So you did know who I was...","TWN":"……您果然認得我。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"으음, 아무래도 오랫동안 보아 왔으니까. 헤이븐 님이 널 점찍어 데려오라고 할 때부터 말이야.","JPN":"そりゃ、長い間見てきたんですもの。ヘイブン様があなたを指名して連れてくるように命じた時からね。","ENG":"Hmm... Well, we’ve seen each other plenty, after Mr. Haven picked you out of the litter.","TWN":"嗯嗯，我也算是看著你長大的，自從天堂先生看中你，讓我把你帶回來開始到現在。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님이 저를요?","JPN":"ヘイブン兄貴が、私を？","ENG":"Mr. Haven picked me?","TWN":"天堂大哥看中我？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼. 네가 가출하고 떠돌던 때부터 줄곧 널 지켜 보셨단다.","JPN":"そう。あなたが家出してさまよってた頃から、ずっとあなたを見守っていらっしゃったの。","ENG":"Of course. He’s been watching you ever since you were living out on the streets.","TWN":"沒錯，打從你離家出走流浪街頭，他就一直有在注意你。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"집으로 돌아갈 낌새가 보이길래 위저드 아이들을 이용해서 널 다치게 만들었고.","JPN":"家に帰りそうだったから、ウィザードの子たちを使ってあなたに怪我させたりもしたわね。","ENG":"Just when we thought you were heading back home, we used our children to hurt you.","TWN":"他看你似乎有打算回家的跡象，於是便派魔法師的孩子打傷你。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭐…… 라고요?","JPN":"なん……ですって？","ENG":"What... did you just say?","TWN":"什……什麼？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드의 소중한 인력이 될 텐데 그냥 보내줄 순 없잖니?","JPN":"ウィザードの大事な人手になるはずなのに、素直に行かせるわけにはいかないでしょう？","ENG":"We couldn't let a potential Wizard member slip through our fingers, could we?","TWN":"你是魔法師看中的人才，當然不能輕易放你走的嘛。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님은 원하는 게 있으면 수단 방법을 가리지 않으시니까. 참 매정하시기도 하지.","JPN":"ヘイブン様は欲しいものには手段を選ばないのよ。なんて冷たい方なのかしら。","ENG":"Mr. Haven doesn’t take no for an answer. Cruel, isn’t it?","TWN":"天堂先生對於想要的東西，一向是不擇手段的，有點冷酷對吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럴 리가…… 헤이븐 형님이 어떻게…….","JPN":"そんな……ヘイブン兄貴がなんで……","ENG":"There’s no way... How could he do...","TWN":"怎麼會……天堂大哥竟然……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};